const fs=require("fs"),path=require("path"),{minify:minify}=require("terser"),CleanCSS=require("clean-css"),PROJECT_ROOT=path.join(__dirname,".."),HTML_FILE=path.join(PROJECT_ROOT,"index.html");function toForwardSlash(e){return e.replace(/\\/g,"/")}async function minifyJS(e){const n=fs.readFileSync(e,"utf8"),r=await minify(n);if(r.error)throw r.error;return r.code}function minifyCSS(e){const n=fs.readFileSync(e,"utf8"),r=(new CleanCSS).minify(n);if(r.errors&&r.errors.length>0)throw r.errors;return r.styles}function getMinifiedPath(e){const n=path.dirname(e),r=path.extname(e),t=path.basename(e,r);return path.join(n,`${t}.min${r}`)}async function processFile(e,n){let r;"js"===n?r=await minifyJS(e):"css"===n&&(r=minifyCSS(e));const t=getMinifiedPath(e);return fs.writeFileSync(t,r,"utf8"),console.log(`Minified: ${toForwardSlash(e)} -> ${toForwardSlash(t)}`),t}function parseVersion(e){const n=e.match(/v?(\d+)\.(\d+)\.(\d+)/);return n?{major:parseInt(n[1]),minor:parseInt(n[2]),patch:parseInt(n[3])}:null}function incrementVersion(e){return e?{...e,patch:e.patch+1}:{major:1,minor:0,patch:1}}function versionToString(e){return`${e.major}.${e.minor}.${e.patch}`}function updateHTMLReferences(e){let n=fs.readFileSync(HTML_FILE,"utf8");const r=new Map;for(const n of e){const e=toForwardSlash(path.relative(PROJECT_ROOT,n)),t=toForwardSlash(getMinifiedPath(e));r.set(e,t)}for(const[e,t]of r){const r=e.replace(/\./g,"\\."),o=new RegExp(r+"(\\?v=[^\"']*)?","g");n=n.replace(o,(n,r)=>{if(r){const n=versionToString(incrementVersion(parseVersion(r.substring(3))));return console.log(`Updated version: ${e}${r} -> ${t}?v=${n}`),`${t}?v=${n}`}return console.log(`Updated reference: ${e} -> ${t}`),t})}fs.writeFileSync(HTML_FILE,n,"utf8")}async function main(){const e=process.argv.slice(2),n=[],r=[];for(const t of e){const e=path.join(PROJECT_ROOT,t);if(!fs.existsSync(e))continue;const o=path.extname(t).toLowerCase();".js"===o?n.push(e):".css"===o&&r.push(e)}console.log(`Found ${n.length} JS files and ${r.length} CSS files to process`);for(const e of n)await processFile(e,"js");for(const e of r)await processFile(e,"css");updateHTMLReferences([...n,...r]),console.log("Done!")}main().catch(e=>{console.error("Error:",e),process.exit(1)});